const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';

function categoryColorOr(bundle: ViewportPaintBundle | null, cat: ElementCategoryToken): string {
  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
