const fs = require('fs');
let src = fs.readFileSync('packages/web/src/Viewport.tsx', 'utf8');

// 1. makeStairVolumeMesh: remove selectedId param
src = src.replace(
  /function makeStairVolumeMesh\(
  stair: Extract<Element, \{ kind: 'stair' \}>,
  elementsById: Record<string, Element>,
  paint: ViewportPaintBundle \| null,
  selectedId\?: string,
\): THREE\.Group \{/,
  \`function makeStairVolumeMesh(
  stair: Extract<Element, { kind: 'stair' }>,
  elementsById: Record<string, Element>,
  paint: ViewportPaintBundle | null,
): THREE.Group {\`
);

// 2. makeStairVolumeMesh: remove stairColor ternary and old mat
src = src.replace(
  /  const stairColor =
    stair\.id === selectedId
      \? \(paint\?\.selection\.selectedColor \?\? '#fcd34d'\)
      : categoryColorOr\(paint, 'stair'\);
  const mat = new THREE\.MeshStandardMaterial\(\{ color: stairColor \}\);/,
  \`  const mat = new THREE.MeshStandardMaterial({
    color: categoryColorOr(paint, 'stair'),
    roughness: paint?.categories.stair.roughness ?? 0.85,
  });\`
);

// 3. makeWallMesh: remove selectedId param
src = src.replace(
  /function makeWallMesh\(
  wall: WallElem,
  elevM: number,
  paint: ViewportPaintBundle \| null,
  selectedId\?: string,
\): THREE\.Mesh \{/,
  \`function makeWallMesh(
  wall: WallElem,
  elevM: number,
  paint: ViewportPaintBundle | null,
): THREE.Mesh {\`
);

// 4. makeWallMesh: remove color ternary, add metalness
src = src.replace(
  /    new THREE\.MeshStandardMaterial\(\{
      color:
        wall\.id === selectedId
          \? \(paint\?\.selection\.selectedColor \?\? '#fb923c'\)
          : categoryColorOr\(paint, 'wall'\),
      roughness: paint\?\.categories\.wall\.roughness \?\? 0\.85,
    \}\),/,
  \`    new THREE.MeshStandardMaterial({
      color: categoryColorOr(paint, 'wall'),
      roughness: paint?.categories.wall.roughness ?? 0.85,
      metalness: paint?.categories.wall.metalness ?? 0.0,
    }),\`
);

// 5. makeWallWithOpenings: remove selectedId param
src = src.replace(
  /function makeWallWithOpenings\(
  wall: WallElem,
  elevM: number,
  hostedDoors: DoorElem\[\],
  hostedWindows: WindowElem\[\],
  paint: ViewportPaintBundle \| null,
  selectedId: string \| undefined,
  evaluator: Evaluator,
\): THREE\.Mesh \{/,
  \`function makeWallWithOpenings(
  wall: WallElem,
  elevM: number,
  hostedDoors: DoorElem[],
  hostedWindows: WindowElem[],
  paint: ViewportPaintBundle | null,
  evaluator: Evaluator,
): THREE.Mesh {\`
);

// 6. makeWallWithOpenings: remove color ternary from wallMat, add metalness
src = src.replace(
  /  const wallMat = new THREE\.MeshStandardMaterial\(\{
    color:
      wall\.id === selectedId
        \? \(paint\?\.selection\.selectedColor \?\? '#fb923c'\)
        : categoryColorOr\(paint, 'wall'\),
    roughness: paint\?\.categories\.wall\.roughness \?\? 0\.85,
  \}\);/,
  \`  const wallMat = new THREE.MeshStandardMaterial({
    color: categoryColorOr(paint, 'wall'),
    roughness: paint?.categories.wall.roughness ?? 0.85,
    metalness: paint?.categories.wall.metalness ?? 0.0,
  });\`
);

// 7. makeWallWithOpenings fallback call
src = src.replace(
  /    return makeWallMesh\(wall, elevM, paint, selectedId\);/,
  '    return makeWallMesh(wall, elevM, paint);'
);

// 8. makeDoorMesh: remove sid param
src = src.replace(
  /function makeDoorMesh\(
  door: Extract<Element, \{ kind: 'door' \}>,
  wall: WallElem,
  elevM: number,
  paint: ViewportPaintBundle \| null,
  sid\?: string,
\) \{/,
  \`function makeDoorMesh(
  door: Extract<Element, { kind: 'door' }>,
  wall: WallElem,
  elevM: number,
  paint: ViewportPaintBundle | null,
) {\`
);

// 9. makeDoorMesh: remove doorColor ternary and old frameMat/panelMat
src = src.replace(
  /  const doorColor = door\.id === sid
    \? \(paint\?\.selection\.selectedColor \?\? '#fde047'\)
    : categoryColorOr\(paint, 'door'\);

  const frameMat = new THREE\.MeshStandardMaterial\(\{ color: doorColor \}\);
  const panelMat = new THREE\.MeshStandardMaterial\(\{ color: doorColor, roughness: 0\.75 \}\);/,
  \`  const frameColor = categoryColorOr(paint, 'door');
  const frameMat = new THREE.MeshStandardMaterial({
    color: frameColor,
    roughness: paint?.categories.door.roughness ?? 0.70,
    metalness: paint?.categories.door.metalness ?? 0.0,
  });
  const panelMat = new THREE.MeshStandardMaterial({
    color: frameColor,
    roughness: paint?.categories.door.roughness ?? 0.70,
  });\`
);

// 10. makeWindowMesh: remove sid param
src = src.replace(
  /function makeWindowMesh\(
  win: Extract<Element, \{ kind: 'window' \}>,
  wall: WallElem,
  elevM: number,
  paint: ViewportPaintBundle \| null,
  sid\?: string,
\) \{/,
  \`function makeWindowMesh(
  win: Extract<Element, { kind: 'window' }>,
  wall: WallElem,
  elevM: number,
  paint: ViewportPaintBundle | null,
) {\`
);

// 11. makeWindowMesh: remove frameColor ternary and old frameMat
src = src.replace(
  /  const frameColor =
    win\.id === sid
      \? \(paint\?\.selection\.selectedColor \?\? '#ddd6fe'\)
      : categoryColorOr\(paint, 'window'\);
  const frameMat = new THREE\.MeshStandardMaterial\(\{ color: frameColor \}\);/,
  \`  const frameMat = new THREE.MeshStandardMaterial({
    color: categoryColorOr(paint, 'window'),
    roughness: paint?.categories.window.roughness ?? 0.60,
    metalness: paint?.categories.window.metalness ?? 0.05,
  });\`
);

// 12. Call sites
src = src.replace(
  'root.add(makeWallWithOpenings(w, elev, doors, wins, paint, selectedId, csgEvaluator));',
  'root.add(makeWallWithOpenings(w, elev, doors, wins, paint, csgEvaluator));'
);
src = src.replace(
  'root.add(makeWallMesh(w, elev, paint, selectedId));',
  'root.add(makeWallMesh(w, elev, paint));'
);
src = src.replace(
  'root.add(makeDoorMesh(e, hw, elev, paint, selectedId));',
  'root.add(makeDoorMesh(e, hw, elev, paint));'
);
src = src.replace(
  'root.add(makeWindowMesh(e, hw, elev, paint, selectedId));',
  'root.add(makeWindowMesh(e, hw, elev, paint));'
);
src = src.replace(
  'root.add(makeStairVolumeMesh(e, elementsById, paint, selectedId));',
  'root.add(makeStairVolumeMesh(e, elementsById, paint));'
);

// 13. Dependency array: remove selectedId
src = src.replace(
  /  \}, \[
    elementsById,
    selectedId,
    viewerCategoryHidden,/,
  '  }, [
    elementsById,
    viewerCategoryHidden,'
);

fs.writeFileSync('packages/web/src/Viewport.tsx', src);
console.log('done');
"

