      '      op.hiddenEdgeColor.set(paint?.selection.selectedColor ?? \\'#fb923c\\');\n' +
      '    }\n\n    ';
    src = src.slice(0, idx) + insert + src.slice(idx);
  }
}

// Remove selectedId from dependency array (may appear with or without leading comma)
src = src.replace(/\n    selectedId,/, '');

// A5. Add selection useEffect - find dep array closing and insert after
// The dep array ends with sectionBoxActive, theme,
if (!src.includes('}, [selectedId]);')) {
