    const altEnd = '    sectionBoxActive,\\n    theme,\\n  ]);';
    console.log('dep array end not found, checking alt');
    const idx2 = src.indexOf('    sectionBoxActive,\n    theme,\n  ]);');
    console.log('alt idx:', idx2);
  }
}

fs.writeFileSync('packages/web/src/Viewport.tsx', src);

