const checks = {
  'OutlinePass import': src.includes(\"import { OutlinePass }\"),
  'outlinePassRef': src.includes('outlinePassRef'),
  'bimPickMapRef': src.includes('bimPickMapRef'),
  'edgeStrength': src.includes('edgeStrength'),
  'pickMap block': src.includes('bimPickMapRef.current = pickMap'),
  'selection useEffect': src.includes('}, [selectedId]);'),
  'NO stair selectedId param': !src.includes('makeStairVolumeMesh(\n  stair') || !src.includes('selectedId?: string'),
  'NO wall selectedId param': !src.match(/function makeWallMesh[\s\S]{0,200}selectedId\?: string/),
  'NO dep selectedId': !/\n    selectedId,/.test(src),
  'NO call selectedId': !src.includes('makeWallMesh(w, elev, paint, selectedId)'),
};
Object.entries(checks).forEach(([k,v]) => console.log(k + ':', v ? 'OK' : 'FAIL'));
